        button#mat-water.active { border-color: #3498db; color: #3498db; box-shadow: 0 0 8px rgba(52, 152, 219, 0.3); }
        button#mat-wall.active { border-color: #bdc3c7; color: #bdc3c7; box-shadow: 0 0 8px rgba(189, 195, 199, 0.3); }
        button#mat-acid.active { border-color: #2ecc71; color: #2ecc71; box-shadow: 0 0 8px rgba(46, 204, 113, 0.3); }
